mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, a.* FROM ( SELECT b.POST_SEQ, b.TITLE, b.CATEGORY, b.USERS_ID, b.VIEW_COUNT, b.CREATED_AT, u.NAME AS AUTHOR_NAME FROM BOARD_POSTS b LEFT JOIN USERS u ON b.USERS_ID = u.ID
AND (b.TITLE LIKE '%' || #{keyword} || '%' OR u.NAME LIKE '%' || #{keyword} || '%')
ORDER BY CREATED_AT DESC ) a ) WHERE rn BETWEEN #{start} AND #{end}

mapper.update:
UPDATE BOARD_POSTS
SET TITLE = #{title},
    CATEGORY = #{category},
    CONTENT = #{content}
WHERE POST_SEQ = #{post_seq}
